import React, { useState } from 'react';
import { portoData, categoryList, statsData } from '../../Data/Porto';
import { ExternalLink, ArrowUpRight } from 'lucide-react';

const statusStyle = {
  Live: 'bg-green-50 text-green-700 border border-green-200',
  Completed: 'bg-blue-50 text-blue-700 border border-blue-200',
  'Open Source': 'bg-amber-50 text-amber-700 border border-amber-200',
};

const Portofolio = () => {
  const [activeCategory, setActiveCategory] = useState('Semua');

  const filtered =
      activeCategory === 'Semua'
          ? portoData
          : portoData.filter((p) => p.category === activeCategory);

  const featured = portoData.filter((p) => p.featured);

  return (
      <section
          id="portofolio"
          aria-label="Portofolio Tim Devitra"
          className="py-24 bg-white"
      >
        <div className="container mx-auto px-6 max-w-6xl">

          {/* ── Header ── */}
          <div className="mb-16">
            <p className="text-sm font-semibold tracking-widest text-primary uppercase mb-3">
              Tim Devitra
            </p>
            <h1 className="text-4xl md:text-5xl font-bold text-gray-900 leading-tight mb-4">
              Portofolio Proyek
            </h1>
            <p className="text-lg text-gray-500 max-w-xl">
              Kumpulan karya nyata yang kami bangun — dari aplikasi web, sistem IoT, hingga solusi open source.
            </p>
          </div>

          {/* ── Stats ── */}
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mb-16">
            {statsData.map((s) => (
                <div
                    key={s.label}
                    className="bg-gray-50 rounded-xl p-5 border border-gray-100"
                >
                  <div className="text-3xl font-bold text-gray-900 mb-1">{s.value}</div>
                  <div className="text-sm text-gray-500">{s.label}</div>
                </div>
            ))}
          </div>

          {/* ── Featured Projects ── */}
          <div className="mb-20">
            <h2 className="text-xl font-semibold text-gray-800 mb-6">Proyek Unggulan</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {featured.map((project, index) => (
                  <article
                      key={project.id}
                      className={`group relative rounded-2xl overflow-hidden border border-gray-200 bg-white hover:shadow-md transition-shadow duration-200 flex flex-col ${
                          index === 0 ? 'md:col-span-2' : ''
                      }`}
                      itemScope
                      itemType="https://schema.org/SoftwareApplication"
                  >
                    {/* Image placeholder */}
                    <div
                        className={`bg-gray-100 ${index === 0 ? 'h-56' : 'h-44'} relative overflow-hidden`}
                    >
                      {project.image ? (
                          <img
                              src={project.image}
                              alt={`Screenshot proyek ${project.title}`}
                              className="w-full h-full object-cover"
                              loading="lazy"
                              width="800"
                              height="400"
                              itemProp="image"
                          />
                      ) : (
                          <div className="w-full h-full flex items-center justify-center text-gray-300 text-4xl font-bold select-none">
                            {project.title.slice(0, 2)}
                          </div>
                      )}
                      <span
                          className={`absolute top-3 right-3 text-xs font-medium px-2.5 py-1 rounded-full ${
                              statusStyle[project.status] ?? 'bg-gray-100 text-gray-600 border border-gray-200'
                          }`}
                      >
                    {project.status}
                  </span>
                    </div>

                    <div className="p-5 flex flex-col flex-1">
                      <div className="flex items-start justify-between gap-2 mb-2">
                        <h3
                            className="text-base font-semibold text-gray-900 leading-snug"
                            itemProp="name"
                        >
                          {project.title}
                        </h3>
                        <span className="text-xs text-gray-400 shrink-0 mt-0.5">{project.year}</span>
                      </div>

                      <p className="text-sm text-gray-500 mb-4 leading-relaxed flex-1" itemProp="description">
                        {project.description}
                      </p>

                      <div className="flex flex-wrap gap-1.5 mb-4">
                        {project.tags.map((tag) => (
                            <span
                                key={tag}
                                className="text-xs bg-gray-100 text-gray-600 px-2 py-0.5 rounded-md"
                            >
                        {tag}
                      </span>
                        ))}
                      </div>

                      <a
                          href={project.url}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="inline-flex items-center gap-1.5 text-sm font-medium text-primary hover:opacity-75 transition-opacity mt-auto"
                          aria-label={`Lihat proyek ${project.title}`}
                          itemProp="url"
                      >
                        Lihat Proyek
                        <ArrowUpRight size={15} />
                      </a>
                    </div>
                  </article>
              ))}
            </div>
          </div>

          {/* ── All Projects ── */}
          <div>
            <div className="flex items-center justify-between flex-wrap gap-4 mb-6">
              <h2 className="text-xl font-semibold text-gray-800">Semua Proyek</h2>

              {/* Category Filter */}
              <nav
                  className="flex flex-wrap gap-2"
                  aria-label="Filter kategori proyek"
              >
                {categoryList.map((cat) => (
                    <button
                        key={cat}
                        onClick={() => setActiveCategory(cat)}
                        className={`text-xs font-medium px-3.5 py-1.5 rounded-full border transition-colors duration-150 ${
                            activeCategory === cat
                                ? 'bg-gray-900 text-white border-gray-900'
                                : 'bg-white text-gray-600 border-gray-200 hover:border-gray-400'
                        }`}
                        aria-pressed={activeCategory === cat}
                    >
                      {cat}
                    </button>
                ))}
              </nav>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-5">
              {filtered.map((project) => (
                  <article
                      key={project.id}
                      className="rounded-xl border border-gray-200 bg-white hover:shadow-sm transition-shadow duration-200 flex flex-col overflow-hidden"
                      itemScope
                      itemType="https://schema.org/SoftwareApplication"
                  >
                    <div className="h-36 bg-gray-100 relative overflow-hidden">
                      {project.image ? (
                          <img
                              src={project.image}
                              alt={`Tampilan proyek ${project.title}`}
                              className="w-full h-full object-cover"
                              loading="lazy"
                              width="600"
                              height="300"
                              itemProp="image"
                          />
                      ) : (
                          <div className="w-full h-full flex items-center justify-center text-gray-300 text-3xl font-bold select-none">
                            {project.title.slice(0, 2)}
                          </div>
                      )}
                    </div>

                    <div className="p-4 flex flex-col flex-1">
                      <div className="flex items-center justify-between mb-1.5">
                        <span className="text-xs text-gray-400 font-medium">{project.category}</span>
                        <span className="text-xs text-gray-400">{project.year}</span>
                      </div>

                      <h3
                          className="text-sm font-semibold text-gray-900 mb-1.5"
                          itemProp="name"
                      >
                        {project.title}
                      </h3>

                      <p
                          className="text-xs text-gray-500 leading-relaxed mb-3 flex-1"
                          itemProp="description"
                      >
                        {project.description}
                      </p>

                      <div className="flex flex-wrap gap-1 mb-3">
                        {project.tags.slice(0, 3).map((tag) => (
                            <span
                                key={tag}
                                className="text-xs bg-gray-100 text-gray-500 px-2 py-0.5 rounded"
                            >
                        {tag}
                      </span>
                        ))}
                        {project.tags.length > 3 && (
                            <span className="text-xs text-gray-400">+{project.tags.length - 3}</span>
                        )}
                      </div>

                      <a
                          href={project.url}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="inline-flex items-center gap-1 text-xs font-medium text-primary hover:opacity-70 transition-opacity"
                          aria-label={`Lihat proyek ${project.title}`}
                          itemProp="url"
                      >
                        <ExternalLink size={12} />
                        Lihat Proyek
                      </a>
                    </div>
                  </article>
              ))}
            </div>

            {filtered.length === 0 && (
                <p className="text-center text-gray-400 py-16 text-sm">
                  Tidak ada proyek dalam kategori ini.
                </p>
            )}
          </div>
        </div>
      </section>
  );
};

export default Portofolio;